mapper.select:
SELECT , c.name as category_name FROM place p LEFT JOIN category c ON p.category_id = c.id
AND p.category_id = #{categoryId}
AND p.status = #{status}
ORDER BY p.id DESC

SELECT , c.name as category_name FROM place p LEFT JOIN category c ON p.category_id = c.id
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.address LIKE CONCAT('%', #{keyword}, '%') OR p.tags LIKE CONCAT('%', #{keyword}, '%'))
AND p.category_id = #{categoryId}
AND p.status = #{status}
ORDER BY p.id DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM place p
AND (p.name LIKE CONCAT('%', #{keyword}, '%') OR p.address LIKE CONCAT('%', #{keyword}, '%') OR p.tags LIKE CONCAT('%', #{keyword}, '%'))
AND p.category_id = #{categoryId}
AND p.status = #{status}

SELECT , c.name as category_name, ROUND(6371 * 2 * ASIN(SQRT( POWER(SIN((#{latitude} - ABS(p.latitude)) * PI() / 180 / 2), 2) + COS(#{latitude} * PI() / 180) * COS(ABS(p.latitude) * PI() / 180) * POWER(SIN((#{longitude} - p.longitude) * PI() / 180 / 2), 2) )), 2) AS distance FROM place p LEFT JOIN category c ON p.category_id = c.id
p.longitude IS NOT NULL AND p.latitude IS NOT NULL AND p.status = 1
AND p.category_id = #{categoryId}
HAVING distance <= #{distance}
ORDER BY distance ASC
LIMIT #{limit}

mapper.update:
UPDATE place
name = #{name}, category_id = #{categoryId}, address = #{address}, longitude = #{longitude}, latitude = #{latitude}, images = #{images}, contact_phone = #{contactPhone}, opening_hours = #{openingHours}, description = #{description}, tags = #{tags}, status = #{status}, update_time = NOW()
WHERE id = #{id}

UPDATE place
SET visit_count = visit_count + 1
WHERE id = #{id}

UPDATE place
SET favorite_count = favorite_count + 1
WHERE id = #{id}

UPDATE place
SET rating = #{rating}
WHERE id = #{id}
